#!/usr/bin/env python3
# scripts/lint-catalog-info.py  — run in CI on catalog-info.yaml changes
import sys, yaml, pathlib

REQUIRED = [
    "genai.io/type",
    "genai.io/primary-model",
    "genai.io/model-tier",
    "genai.io/data-class",
    "genai.io/pii-in-prompts",
    "genai.io/golden-path",
    "genai.io/cost-center",
]

VALID_VALUES = {
    "genai.io/type": {
        "rag-application","agent-workflow","llm-gateway",
        "embedding-service","fine-tuned-model","eval-pipeline","prompt-library",
    },
    "genai.io/model-tier": {"standard","premium","admin"},
    "genai.io/data-class": {"public","internal","confidential","restricted"},
    "genai.io/golden-path": {"rag","agent","gateway","none"},
    "genai.io/pii-in-prompts": {"true","false"},
}

# Type-specific required co-annotations
CO_REQUIRED = {
    "rag-application": ["genai.io/vector-store","genai.io/chunk-size","genai.io/retrieval-k"],
    "agent-workflow":  ["genai.io/agent-max-steps","genai.io/human-in-loop"],
    "fine-tuned-model":["genai.io/base-model-id"],
}

def lint(path: str) -> list[str]:
    doc = yaml.safe_load(pathlib.Path(path).read_text())
    annots = doc.get("metadata", {}).get("annotations", {})
    errors = []

    for key in REQUIRED:
        if key not in annots:
            errors.append(f"Missing required annotation: {key}")
        elif key in VALID_VALUES and annots[key] not in VALID_VALUES[key]:
            errors.append(
                f"Invalid value '{annots[key]}' for {key}. "
                f"Allowed: {sorted(VALID_VALUES[key])}"
            )

    comp_type = annots.get("genai.io/type","")
    for key in CO_REQUIRED.get(comp_type, []):
        if key not in annots:
            errors.append(f"Type '{comp_type}' requires annotation: {key}")

    return errors

if __name__ == "__main__":
    path = sys.argv[1]
    errors = lint(path)
    if errors:
        print(f"catalog-info.yaml linting FAILED ({path}):")
        for e in errors:
            print(f"  ✗ {e}")
        sys.exit(1)
    print(f"catalog-info.yaml linting passed: {path}")
